(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('2ae0d163-eab5-406c-92d8-b0619823d29e', 'Based on the texts, how would the author of Text 2 most likely respond to the causal claim in Text 1?', 'Text 1
Text 1 assigns causal primacy to the re-dating of a contested artifact in cognitive neuroscience, treating X as the engine of the observed pattern.

Text 2
Accepting the correlation Text 1 documents, this account nonetheless contends that the routinization of a once-heretical procedure and that pattern are alike downstream of a deeper construal, so that what Text 1 elevates to a primary cause is, on closer inspection, a secondary epiphenomenon its framework is constitutively unable to name.', 'passage', '[{"id":"A","text":"Text 2''s author accepts the empirical correlation Text 1 documents. Yet the author reframes Text 1''s privileged cause as a secondary epiphenomenon of a deeper variable the first framework cannot name —given the dependency the text declines to name.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"B","text":"Text 2''s author accepts the empirical correlation Text 1 documents. Yet the author objects that the correlation is statistical noise unlikely to replicate in further samples —given the dependency the text declines to name.","is_correct":false,"explanation":"[Reciprocal Error] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"Text 2''s author accepts the empirical correlation Text 1 documents. Yet the author attributes to Text 1 the very deeper-cause claim that belongs to the second account —given the dependency the text declines to name.","is_correct":false,"explanation":"[Reverse Trap] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"Text 2''s author accepts the empirical correlation Text 1 documents. Yet the author concludes that the phenomenon should be abandoned as an object of study entirely —given the dependency the text declines to name.","is_correct":false,"explanation":"[Speculative Narrative] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'A', 'Logical Reconstruction:
Step 1: Text 1 assigns causal primacy to a named variable.
Step 2: Text 2 accepts the observation but relocates causation to an unnamed deeper variable.
Step 3: Distinguish an ontological reframing from a statistical objection.
Step 4: Only the choice naming the epiphenomenon reframing captures Text 2''s move.

Key Explanation: Choice A is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice B [Reciprocal Error]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [Reverse Trap]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [Speculative Narrative]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of ontological reframing under full empirical agreement: Text 2 accepts every observation yet relocates the causal primacy Text 1 asserts.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"cross_text_response","rw_format":"text_1_text_2","challenge_key":"CTC"}'::jsonb, true, now(), now());
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('82cbbe04-355a-45c6-8573-5033d2388d7c', 'Which choice best states the main idea of the text?', 'Within cognitive neuroscience, the re-dating of a contested artifact has long been read as straightforward progress, a reading that a coalition of field surveyors—whose archives, only recently catalogued, complicate the received chronology—did much to entrench. What that account treats as predictive coding, however, the measured asymmetry reframes: the apparent advance, far from being intrinsic, was conditioned by an institutional metaplasticity that the standard narrative cannot model. Granting that the correlation is genuine, one must still resist the inference that it is causal, for the same configuration recurs only under conditions the standard account leaves tacit.', 'passage', '[{"id":"A","text":"Read as a whole, the passage advances a qualified central claim. A documented correlation is real but not causal, since the same pattern recurs where the supposed mechanism is absent —given the dependency the text declines to name.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"B","text":"Read as a whole, the passage advances a qualified central claim. The opening impression of straightforward progress is, in fact, the passage''s settled thesis —given the dependency the text declines to name.","is_correct":false,"explanation":"[False Lead] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"Read as a whole, the passage advances a qualified central claim. Because the pattern is causal, the institutional condition it produces must be its effect rather than its source —given the dependency the text declines to name.","is_correct":false,"explanation":"[Reciprocal Error] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"Read as a whole, the passage advances a qualified central claim. No correlation of this kind can ever, in any field, license a causal inference —given the dependency the text declines to name.","is_correct":false,"explanation":"[Over-Extrapolation] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'A', 'Logical Reconstruction:
Step 1: The opening sentence is a False Lead: the view the author complicates.
Step 2: The middle concedes the correlation is genuine.
Step 3: The final clause draws the non-obvious implication: genuine but non-causal.
Step 4: The thesis is the synthesis of concession and implication, not any single sentence.

Key Explanation: Choice A is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice B [False Lead]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [Reciprocal Error]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [Over-Extrapolation]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of False-Lead architecture requiring synthesis of a mid-passage concession with a counter-intuitive final structural implication.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"main_idea","rw_format":"passage_mc","challenge_key":"CID"}'::jsonb, true, now(), now());
