(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('62d9fb43-3488-40da-abc7-ecaf5554947b', 'Which choice best uses data from the table to evaluate the researchers'' hypothesis?', 'Researchers compared soil-carbon storage under two methods across two depths after twenty years. They hypothesize that Method A increases storage relative to Method B at shallow depth, but that at deep depth the relationship inverts.

The table summarizes the results.

| Method | Shallow (20 yr) | Deep (20 yr) |
| --- | --- | --- |
| A | $23\text{ g/kg}$ | $30\text{ g/kg}$ |
| B | $18\text{ g/kg}$ | $16\text{ g/kg}$ |', 'passage', '[{"id":"A","text":"At deep depth, A recorded $30\\text{ g/kg}$ versus B''s $16\\text{ g/kg}$. Read from the wrong row, this cites deep-depth values to judge a shallow-depth claim and misverifies the inversion —once the surface chronology is set aside, in the passage''s own terms, as the argument is staged, given the stated qualifiers.","is_correct":false,"explanation":"[Data Misread] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"B","text":"At shallow depth, A recorded $23\\text{ g/kg}$ versus B''s $18\\text{ g/kg}$. A exceeds B at shallow depth, and since A also exceeds B at deep depth, only the shallow case fits while the inversion fails — so this supports the claim only where both rows are read together —once the surface chronology is set aside.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"C","text":"Across the shallow row, the two methods differ by $5\\text{ g/kg}$. This is an accurate shallow-row gap but says nothing about whether the relationship inverts at depth —once the surface chronology is set aside, given the stated qualifiers, on the evidence presented, within the limits set out.","is_correct":false,"explanation":"[True-But-Irrelevant] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"Method B''s storage declines from shallow to deep by $2\\text{ g/kg}$. This is an accurate within-method trend but does not compare A and B as the hypothesis requires —once the surface chronology is set aside, on the evidence presented, within the limits set out, as the text finally frames it.","is_correct":false,"explanation":"[Partial Match] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'B', 'Logical Reconstruction:
Step 1: Identify shallow cells: A=$23$, B=$18$ (A>B).
Step 2: Identify deep cells: A=$30$, B=$16$ — verify whether A>B inverts.
Step 3: The hypothesis needs the shallow advantage AND a deep inversion.
Step 4: Only the choice that compares both rows can confirm or deny the full conditional.

Key Explanation: Choice B is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice A [Data Misread]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [True-But-Irrelevant]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [Partial Match]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of double-conditional quantitative verification requiring cell-level calculation across both the primary case and the inversion case.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"quantitative_table","rw_format":"table_chart","challenge_key":"COE_Q"}'::jsonb, true, now(), now());
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('d10394c9-a109-4ae9-8a3a-9d7ef9211d98', 'Which choice most logically and necessarily completes the text, based only on the information given above?', 'In economic history, the model holds that A produces B, and that B in turn produces C; where C is the observable signature of the process, its absence is recorded. The text notes that a competing inhibitor could also, in principle, prevent C, but it does not establish whether that factor is present, nor does it report the status of B. The account stops short of stating what the absence of C entails.', 'passage', '[{"id":"A","text":"It follows that the absent C was caused by an outside inhibitor. Because some external factor can block C, the observed absence proves that factor was at work —once the surface chronology is set aside.","is_correct":false,"explanation":"[Speculative Narrative] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"B","text":"It follows that A did not occur. Because A produces B and B produces C, the contrapositive yields not-A from not-C, using only the stated links —once the surface chronology is set aside.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."},{"id":"C","text":"It follows that a competing inhibitor must be responsible for the missing C. Because the text mentions this factor, its mere possibility is enough to fix the cause —once the surface chronology is set aside.","is_correct":false,"explanation":"[Affirming the Consequent] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"It follows that B was elevated rather than absent. Because C is absent, its precursor must have risen rather than failed —once the surface chronology is set aside.","is_correct":false,"explanation":"[Speculative Narrative] Grounded in passage language but fails on a specific qualifier in its second sentence."}]'::jsonb, 'B', 'Logical Reconstruction:
Step 1: State the chain: A → B → C.
Step 2: Observe ¬C.
Step 3: Apply the contrapositive: ¬C → ¬B → ¬A, importing no external cause.
Step 4: Reject any choice that names an unverified alternative cause as a speculative leap.

Key Explanation: Choice B is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice A [Speculative Narrative]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice C [Affirming the Consequent]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice D [Speculative Narrative]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of contrapositive mechanistic chain in which a plausible alternative cause is named but never ruled out, baiting a speculative completion.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Information and Ideas', 'Inferences', 'reading_writing', 'information', 'INF', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"general","rw_format":"passage_mc","challenge_key":"INF"}'::jsonb, true, now(), now());
